// RA-649 — Step 1: Read last processed update_id from Supabase
// Uses native fetch() — n8n v2 Code node, no $http

const SUPABASE_URL = 'https://zbryrmxmgfmslqzizsto.supabase.co';
const SUPABASE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY || '';

let lastUpdateId = 0;
try {
  const resp = await fetch(
    `${SUPABASE_URL}/rest/v1/settings?key=eq.telegram_last_update_id&select=value`,
    {
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
      }
    }
  );
  const rows = await resp.json();
  if (rows && rows.length > 0) {
    lastUpdateId = parseInt(rows[0].value, 10) || 0;
  }
} catch (err) {
  // Non-fatal — fall back to 0 (may re-process recent messages once)
  console.log('Supabase read error (non-fatal):', err.message);
}

return [{ json: { lastUpdateId } }];

// RA-649 — Step 2: Call Telegram getUpdates with offset
// Only returns updates AFTER lastUpdateId

const BOT_TOKEN = process.env.TELEGRAM_BOT_TOKEN || '';
const lastUpdateId = $input.first().json.lastUpdateId;
const offset = lastUpdateId + 1;

if (!BOT_TOKEN) {
  throw new Error('TELEGRAM_BOT_TOKEN env var not set in n8n');
}

const resp = await fetch(
  `https://api.telegram.org/bot${BOT_TOKEN}/getUpdates?offset=${offset}&timeout=0&limit=10`
);

if (!resp.ok) {
  throw new Error(`getUpdates HTTP ${resp.status}: ${await resp.text()}`);
}

const data = await resp.json();
const updates = (data.result || []).filter(u => u.message && u.message.text);

if (updates.length === 0) {
  // No new messages — pass an empty sentinel so downstream nodes no-op
  return [{ json: { noUpdates: true, lastUpdateId } }];
}

// Return each message as a separate item
return updates.map(u => ({
  json: {
    update_id: u.update_id,
    chat_id: String(u.message.chat.id),
    user_id: String(u.message.from.id),
    text: (u.message.text || '').trim(),
    lastUpdateId,
  }
}));

// RA-649 — Step 3a: Parse command and build reply
// Allowed user IDs (matches ALLOWED_USERS in telegram-bot/.env)
const ALLOWED = ['8792816988'];

const item = $input.first().json;
const chatId = item.chat_id;
const userId = item.user_id;
const text = item.text || '';

// Security: only respond to authorised users
if (!ALLOWED.includes(userId)) {
  return [{ json: { chatId, reply: '⛔ Unauthorised.', skip: false } }];
}

// Parse command
const cmd = text.split(' ')[0].toLowerCase();
let reply = '';

switch (cmd) {
  case '/status': {
    // Fetch live status from Pi-CEO Railway backend
    let statusText = '';
    try {
      const resp = await fetch('https://pi-dev-ops-production.up.railway.app/api/status', {
        headers: { 'Content-Type': 'application/json' }
      });
      if (resp.ok) {
        const d = await resp.json();
        const sessions = d.sessions || {};
        const autonomy = d.autonomy || {};
        const eff = (autonomy.effective_autonomy || {}).effective_autonomy_pct;
        const lastPoll = autonomy.last_poll_ago_s != null ? `${Math.round(autonomy.last_poll_ago_s / 60)}m ago` : 'never';
        statusText = (
          `🤖 *Pi-CEO Status*\n` +
          `Active sessions: ${sessions.active || 0}/${sessions.max || 3}\n` +
          `Autonomy poll: ${lastPoll}\n` +
          `Effective autonomy: ${eff != null ? eff + '%' : 'n/a'}\n` +
          `Stale: ${autonomy.stale ? '⚠️ YES' : '✅ no'}`
        );
      } else {
        statusText = `⚠️ Status endpoint returned HTTP ${resp.status}`;
      }
    } catch (err) {
      statusText = `❌ Could not reach Pi-CEO: ${err.message}`;
    }
    reply = statusText;
    break;
  }

  case '/triage': {
    // Fetch recent Pi-SEO triage summary from Supabase scan-results (last 24h tickets)
    reply = (
      `📋 *Triage summary*\n` +
      `Use the Pi-CEO dashboard for detailed scan results.\n` +
      `https://pi-dev-ops-production.up.railway.app/`
    );
    break;
  }

  case '/alerts': {
    // Fetch last monitor digest summary
    try {
      const resp = await fetch('https://pi-dev-ops-production.up.railway.app/api/monitor/digest', {
        headers: { 'Content-Type': 'application/json' }
      });
      if (resp.ok) {
        const d = await resp.json();
        const health = d.portfolio_health || 0;
        const alertCount = (d.alerts || []).length;
        const critCount = (d.alerts || []).filter(a => a.severity === 'critical').length;
        reply = (
          `🔔 *Alerts*\n` +
          `Portfolio health: ${health}/100\n` +
          `Total alerts: ${alertCount}\n` +
          `Critical: ${critCount}\n` +
          `Last run: ${d.generated_at || 'unknown'}`
        );
      } else {
        reply = `⚠️ Monitor digest returned HTTP ${resp.status}`;
      }
    } catch (err) {
      reply = `❌ Could not reach monitor: ${err.message}`;
    }
    break;
  }

  case '/help':
  default:
    reply = (
      `🤖 *Pi-CEO Bot*\n\n` +
      `/status — live session + autonomy stats\n` +
      `/alerts — latest Pi-SEO monitor digest\n` +
      `/triage — link to Pi-SEO triage dashboard\n` +
      `/help — this message`
    );
    break;
}

return [{ json: { chatId, reply, update_id: item.update_id, lastUpdateId: item.lastUpdateId } }];

// RA-649 — Step 4: Send reply via Telegram sendMessage
const BOT_TOKEN = process.env.TELEGRAM_BOT_TOKEN || '';
const item = $input.first().json;

if (!item.chatId || !item.reply) {
  return [{ json: { sent: false, reason: 'no chatId or reply' } }];
}

const payload = {
  chat_id: item.chatId,
  text: item.reply,
  parse_mode: 'Markdown',
  disable_web_page_preview: true,
};

const resp = await fetch(`https://api.telegram.org/bot${BOT_TOKEN}/sendMessage`, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(payload),
});

const result = await resp.json();
if (!result.ok) {
  console.log('sendMessage error:', JSON.stringify(result));
}

return [{ json: { sent: result.ok, update_id: item.update_id, lastUpdateId: item.lastUpdateId } }];

// RA-649 — Step 5: Persist the highest processed update_id back to Supabase
// This prevents re-processing messages on the next poll cycle

const SUPABASE_URL = 'https://zbryrmxmgfmslqzizsto.supabase.co';
const SUPABASE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY || '';

const item = $input.first().json;
const newUpdateId = item.update_id || item.lastUpdateId || 0;

if (!newUpdateId) {
  return [{ json: { persisted: false, reason: 'no update_id to save' } }];
}

// Upsert: update if row exists, insert if not
const resp = await fetch(
  `${SUPABASE_URL}/rest/v1/settings`,
  {
    method: 'POST',
    headers: {
      'apikey': SUPABASE_KEY,
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'Content-Type': 'application/json',
      'Prefer': 'resolution=merge-duplicates',
    },
    body: JSON.stringify({ key: 'telegram_last_update_id', value: String(newUpdateId) }),
  }
);

const ok = resp.ok || resp.status === 201 || resp.status === 200;
console.log(`Persisted update_id=${newUpdateId} to Supabase (HTTP ${resp.status})`);

return [{ json: { persisted: ok, update_id: newUpdateId } }];
